1513	// ClosureGate inspects a bead and returns nil iff the close is safe. It
1514	// rejects only the specific shapes that caused the 2026-04-18/20
1515	// review-malfunction incidents:
1516	//
1517	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
1518	//     closing_commit_sha. Rejected by the execution-evidence check —
1519	//     closing_commit_sha must be non-empty OR at least one event must exist.
1520	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
1521	//     body is empty. Rejected — APPROVE with no rationale is exactly the
1522	//     parse-mis-extract shape the reviewer bug produced.
1523	//
1524	// Beads without a review step (--no-review, no Reviewer configured, already-
1525	// satisfied paths) pass the gate as long as they carry execution evidence.
1526	// This keeps the surface small: the gate catches known-bad shapes, not every
1527	// conceivable edge case. Additional invariants belong in future dedicated
1528	// beads so the rejection reason stays auditable.
1529	func ClosureGate(b *Bead) error {
1530		if b == nil {
1531			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
1532		}
1533		hasClosingCommit := false
1534		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
1535			hasClosingCommit = true
1536		}
1537		events := decodeBeadEvents(b.Extra["events"])
1538		// Externalized events still count as evidence for the gate. We only need
1539		// to know whether *some* event history exists, not iterate it; the
1540		// gate's APPROVE-with-empty-rationale check below relies on inline events
1541		// (the verdict is recorded before externalization).
1542		hasAttachedEvents := hasEventsAttachment(b)
1543		// Reject the axon-c5cc071a shape: no events AND no closing commit.
1544		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
1545			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
1546		}
1547		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
1548		for _, e := range events {
1549			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
1550				if strings.TrimSpace(e.Body) == "" {
1551					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
1552				}
1553			}
1554		}
1555		return nil
1556	}
